+    local procedure GetNonDeductibleVATAmountInJobCurrency(GenJnlLine: Record "Gen. Journal Line"): Decimal
+    var
+        JobCurrency: Decimal;
+    begin
+        // Convert Non-Deductible VAT Amount to Job Currency
