+        // We need to convert it to the Job's currency (GenJnlLine."Job Currency Code")
+        
+        // If Job has no currency (LCY), convert from document currency to LCY
+        if GenJnlLine."Job Currency Code" = '' then
+            exit(CurrencyExchRate.ExchangeAmtFCYToLCY(
+                GenJnlLine."Posting Date",
+                GenJnlLine."Currency Code",
+                GenJnlLine."Non-Deductible VAT Amount",
+                GenJnlLine."Currency Factor"));
+        
+        // If Job currency is same as document currency, use directly
+        if GenJnlLine."Job Currency Code" = GenJnlLine."Currency Code" then
+            exit(GenJnlLine."Non-Deductible VAT Amount");
+        
+        // Otherwise, convert from LCY to Job currency
+        // First convert from document currency to LCY
+        JobCurrency := CurrencyExchRate.ExchangeAmtFCYToLCY(
+            GenJnlLine."Posting Date",
+            GenJnlLine."Currency Code",
+            GenJnlLine."Non-Deductible VAT Amount",
+            GenJnlLine."Currency Factor");
+        
+        // Then convert from LCY to Job currency
+        exit(CurrencyExchRate.ExchangeAmtLCYToFCY(
+            GenJnlLine."Posting Date",
+            GenJnlLine."Job Currency Code",
+            JobCurrency,
+            GenJnlLine."Job Currency Factor"));
+    end;
